import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.CNG7EpJN.js";const c=JSON.parse('{"title":"管理ダッシュボード","description":"","frontmatter":{"title":"管理ダッシュボード"},"headers":[],"relativePath":"tenant/03-dashboard.md","filePath":"tenant/03-dashboard.md"}'),h={name:"tenant/03-dashboard.md"};function l(i,t,o,n,b,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="_3-管理ダッシュボード" tabindex="-1">3. 管理ダッシュボード <a class="header-anchor" href="#_3-管理ダッシュボード" aria-label="Permalink to &quot;3. 管理ダッシュボード&quot;">​</a></h1><p>管理ダッシュボードは、店長・副店長・店舗責任者が毎日使う店舗運営の入口です。POSLA の主要機能は、左側メニューの大分類と、上部のサブタブに分かれています。</p><p>この章では、画面全体の見方と、日々の運営で最初に確認する <strong>運営管理</strong> の使い方を説明します。</p><h2 id="画面の基本構成" tabindex="-1">画面の基本構成 <a class="header-anchor" href="#画面の基本構成" aria-label="Permalink to &quot;画面の基本構成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場所</th><th>内容</th></tr></thead><tbody><tr><td>左側メニュー</td><td>運営管理、メニュー管理、プラン・コース、テーブル・フロア、在庫・レシピ、レポート、店舗設定、テイクアウト、AIアシスタント、予約管理、シフト管理を切り替えます</td></tr><tr><td>上部サブタブ</td><td>選択した大分類の中で、細かい画面を切り替えます</td></tr><tr><td>ヘッダー</td><td>店舗名、店舗切替、ログイン中ユーザー、取扱説明書、パスワード変更、ログアウトを表示します</td></tr><tr><td>業務ショートカット</td><td>ハンディPOS、KDS、POSレジ、お客様注文画面を別タブで開きます</td></tr><tr><td>右下のサポートガイド</td><td>FAQ、症状別案内、エラー番号検索を開きます</td></tr><tr><td>右下のキャッシュリセット</td><td>画面表示が古い、ボタンが反応しないなどのときにブラウザ側キャッシュをリセットします</td></tr></tbody></table><p>複数店舗を管理している場合は、操作前に必ずヘッダーの店舗名を確認してください。選択中の店舗に対して、メニュー、予約、シフト、売上、設定が読み書きされます。</p><h2 id="左側メニューの役割" tabindex="-1">左側メニューの役割 <a class="header-anchor" href="#左側メニューの役割" aria-label="Permalink to &quot;左側メニューの役割&quot;">​</a></h2><table tabindex="0"><thead><tr><th>メニュー</th><th>主な用途</th></tr></thead><tbody><tr><td>運営管理</td><td>今日の要注意、全体検索、売上ドリル、初期設定、端末稼働、カート離脱を確認</td></tr><tr><td>メニュー管理</td><td>カテゴリ、オプション、店舗メニュー、限定メニュー、翻訳、CSV一括更新を管理</td></tr><tr><td>プラン・コース</td><td>食べ放題プラン、プラン専用メニュー、コース料理を管理</td></tr><tr><td>テーブル・フロア</td><td>卓、QR、個別QR、フロアマップを管理</td></tr><tr><td>在庫・レシピ</td><td>原材料、レシピ、低在庫、注文時の在庫減算を管理</td></tr><tr><td>レポート</td><td>売上、レジ、注文履歴、回転率、スタッフ評価、満足度、併売分析を確認</td></tr><tr><td>店舗設定</td><td>営業日区切り、税率、レジ、プリンタ、テイクアウト、予約URL、外観を設定</td></tr><tr><td>テイクアウト</td><td>テイクアウト注文、SLA警告、梱包、通知、受取遅れ、返金対応を管理</td></tr><tr><td>AIアシスタント</td><td>SNS文案、売上分析、需要予測、競合調査などを依頼</td></tr><tr><td>予約管理</td><td>予約台帳、当日受付、顧客台帳、コース、予約設定、予約レポートを管理</td></tr><tr><td>シフト管理</td><td>週間シフト、希望提出、勤怠、テンプレート、当日・ヘルプを管理</td></tr></tbody></table><p>スタッフロールでログインした場合は、店舗運営メニューの代わりにスマホ向けのスタッフ画面が中心になります。スタッフ画面では、今日の勤務、勤怠打刻、未対応、マイシフト、希望提出、交代/欠勤申請を扱います。</p><h2 id="運営管理" tabindex="-1">運営管理 <a class="header-anchor" href="#運営管理" aria-label="Permalink to &quot;運営管理&quot;">​</a></h2><p>運営管理は、店長が「今日まず何を見るか」を確認するための集約画面です。複数の詳細画面を開く前に、ここで異常や未対応を拾います。</p><table tabindex="0"><thead><tr><th>サブタブ</th><th>確認できること</th><th>主な使い方</th></tr></thead><tbody><tr><td>運営コックピット</td><td>未会計、未締め、予約、シフト不足、品切れ/低在庫、低評価、障害/エラー、テイクアウト遅延</td><td>開店前、ピーク前、閉店前に警告件数を確認</td></tr><tr><td>全体検索</td><td>注文、予約、顧客、商品、スタッフ、エラーを横断検索</td><td>電話問い合わせ、クレーム、注文確認、エラー番号調査</td></tr><tr><td>売上ドリル</td><td>日別 → 商品 → 注文 → 会計履歴</td><td>「どの商品が、どの注文で、どう会計されたか」を追跡</td></tr><tr><td>初期設定</td><td>店舗、カテゴリ、メニュー、卓・QR、スタッフ、KDS、予約、テイクアウト、在庫、レシピ、プラン、コース</td><td>導入時や新店舗追加時の抜け漏れ確認</td></tr><tr><td>端末稼働</td><td>KDS、ハンディ、レジ、セルフメニューの最終通信時刻</td><td>端末が止まっていないか、古い端末が残っていないか確認</td></tr><tr><td>カート離脱</td><td>一度カートに入れて外された商品、注文内キャンセル商品</td><td>写真、価格、説明、オプション、売り切れ表示の改善判断</td></tr></tbody></table><h3 id="運営コックピットで見る警告" tabindex="-1">運営コックピットで見る警告 <a class="header-anchor" href="#運営コックピットで見る警告" aria-label="Permalink to &quot;運営コックピットで見る警告&quot;">​</a></h3><table tabindex="0"><thead><tr><th>カード</th><th>見ているデータ</th><th>店舗側の対応</th></tr></thead><tbody><tr><td>未会計</td><td><code>paid</code> / <code>cancelled</code> 以外の注文</td><td>レジ画面で会計待ちの卓・注文を確認</td></tr><tr><td>未締め</td><td>当日のレジ開局と締めの記録</td><td>閉店前にレジ締め、締め忘れ警告を確認</td></tr><tr><td>予約</td><td>当日の保留・確定・着席中予約と遅刻注意</td><td>予約台帳で遅刻、no-show、席割当を確認</td></tr><tr><td>シフト不足</td><td>当日の未打刻と未対応の交代/欠勤申請</td><td>シフト管理の当日・ヘルプで対応</td></tr><tr><td>品切れ/低在庫</td><td>店舗メニューの売り切れ、原材料の低在庫</td><td>メニュー管理、在庫・レシピで更新</td></tr><tr><td>低評価</td><td>本日の1〜2点評価</td><td>満足度分析で理由、品目、時間帯を確認</td></tr><tr><td>障害/エラー</td><td>直近24時間のAPIエラー</td><td>エラー監視またはサポートへ連絡</td></tr><tr><td>テイクアウト遅延</td><td>受取時刻15分以内または超過リスクの未完了注文</td><td>テイクアウト管理で調理・梱包・通知を確認</td></tr></tbody></table><p>運営コックピットは、各詳細画面の代替ではありません。件数が出ている場合は、該当する詳細画面に移動して対応してください。</p><h2 id="全体検索" tabindex="-1">全体検索 <a class="header-anchor" href="#全体検索" aria-label="Permalink to &quot;全体検索&quot;">​</a></h2><p>全体検索は、2文字以上のキーワードで、店舗内の主要データをまとめて検索します。</p><p>検索対象:</p><ul><li>注文ID、注文内容、注文者名、電話番号</li><li>予約者名、電話番号、メール、予約メモ</li><li>顧客台帳の名前、電話番号、好み、注意点</li><li>本部メニュー、店舗限定メニュー</li><li>スタッフ名、ユーザー名</li><li>エラー番号、エラーコード、エラーメッセージ</li></ul><p>電話問い合わせやクレーム対応では、まず名前、電話番号、注文ID、予約者名のいずれかで検索してください。検索結果は確認用であり、編集や返金などの操作は各詳細画面で行います。</p><h2 id="売上ドリルダウン" tabindex="-1">売上ドリルダウン <a class="header-anchor" href="#売上ドリルダウン" aria-label="Permalink to &quot;売上ドリルダウン&quot;">​</a></h2><p>売上ドリルダウンでは、期間を選んで次の順に深掘りできます。</p><ol><li>日別売上</li><li>その日の商品別売上</li><li>その商品を含む注文一覧</li><li>注文詳細と会計履歴</li></ol><p>売上ドリルは、商品改善や問い合わせ対応に使います。売上集計は会計済み注文を中心に確認します。返金、取消、外部決済控えの詳細は、必要に応じてレジ分析や取引ジャーナルも確認してください。</p><h2 id="初期設定チェックリスト" tabindex="-1">初期設定チェックリスト <a class="header-anchor" href="#初期設定チェックリスト" aria-label="Permalink to &quot;初期設定チェックリスト&quot;">​</a></h2><p>初期設定では、POSLAを営業で使う前に必要な設定の有無を確認します。</p><table tabindex="0"><thead><tr><th>項目</th><th>完了の目安</th></tr></thead><tbody><tr><td>店舗基本情報</td><td>店舗が有効で、選択できる</td></tr><tr><td>カテゴリ</td><td>メニュー分類が1件以上ある</td></tr><tr><td>メニュー</td><td>本部メニューまたは店舗限定メニューが1件以上ある</td></tr><tr><td>卓・QR</td><td>有効なテーブルが1卓以上ある</td></tr><tr><td>スタッフ</td><td>manager または staff の所属ユーザーがいる</td></tr><tr><td>KDS</td><td>有効なKDSステーションがある</td></tr><tr><td>予約</td><td>予約設定が作成されている</td></tr><tr><td>テイクアウト</td><td>テイクアウト設定があり、受付が有効になっている</td></tr><tr><td>在庫</td><td>原材料が登録されている</td></tr><tr><td>レシピ</td><td>メニューと原材料のレシピが登録されている</td></tr><tr><td>プラン</td><td>食べ放題などの時間制プランが登録されている</td></tr><tr><td>コース</td><td>予約やコース提供に使うコースが登録されている</td></tr></tbody></table><p>すべての店舗がすべての項目を必ず使うわけではありません。たとえばテイクアウトを運用しない店舗では、テイクアウトが未完了でも営業はできます。ただし、予約・テイクアウト・在庫・コースを使う予定がある場合は、営業開始前に必ず設定してください。</p><h2 id="端末稼働状況" tabindex="-1">端末稼働状況 <a class="header-anchor" href="#端末稼働状況" aria-label="Permalink to &quot;端末稼働状況&quot;">​</a></h2><p>端末稼働状況では、KDS、ハンディ、レジ、セルフメニューの最終通信時刻を確認します。</p><p>見るポイント:</p><ul><li>KDSやレジの最終通信が古い場合、端末の電源、Wi-Fi、ログイン状態を確認する</li><li>ハンディ端末が複数ある場合、使っていない端末が残っていないか確認する</li><li>セルフメニューの最終通信がない場合、QR掲示、テーブル開放、注文画面URLを確認する</li><li>端末専用アカウントは人件費・勤怠の対象ではないため、人のスタッフアカウントと混ぜない</li></ul><h2 id="カート離脱・キャンセル分析" tabindex="-1">カート離脱・キャンセル分析 <a class="header-anchor" href="#カート離脱・キャンセル分析" aria-label="Permalink to &quot;カート離脱・キャンセル分析&quot;">​</a></h2><p>カート離脱では、お客様が商品を一度カートに入れた後、外した商品を確認できます。注文履歴に残る注文内キャンセルも、環境に記録がある場合は同じ画面に表示されます。</p><p>活用例:</p><ul><li>写真と実物の印象が違う商品を見つける</li><li>価格を見て外されやすい商品を見つける</li><li>必須オプションが分かりにくい商品を見つける</li><li>売り切れや説明不足で注文をやめた可能性を確認する</li><li>セット化、写真差し替え、説明文追加の優先順位を決める</li></ul><h2 id="ロール別の表示" tabindex="-1">ロール別の表示 <a class="header-anchor" href="#ロール別の表示" aria-label="Permalink to &quot;ロール別の表示&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>主に表示される内容</th></tr></thead><tbody><tr><td>オーナー</td><td>複数店舗管理、本部機能、契約・決済設定、ユーザー管理</td></tr><tr><td>マネージャー</td><td>担当店舗のメニュー、注文、会計、在庫、シフト、レポート、店舗設定</td></tr><tr><td>スタッフ</td><td>勤怠打刻、マイシフト、希望シフト提出</td></tr></tbody></table><p>表示されないタブがある場合は、権限または所属店舗が不足している可能性があります。</p><h2 id="店舗を切り替える" tabindex="-1">店舗を切り替える <a class="header-anchor" href="#店舗を切り替える" aria-label="Permalink to &quot;店舗を切り替える&quot;">​</a></h2><p>複数店舗に所属している場合は、画面上部の店舗セレクターから操作対象の店舗を選びます。選択した店舗に対して、メニュー、注文、レポートなどの操作が行われます。</p><h2 id="サポートガイドを使う-右下の-📚-ボタン" tabindex="-1">サポートガイドを使う (右下の 📚 ボタン) <a class="header-anchor" href="#サポートガイドを使う-右下の-📚-ボタン" aria-label="Permalink to &quot;サポートガイドを使う (右下の 📚 ボタン)&quot;">​</a></h2><p>管理画面右下の <strong>「📚 サポートガイド」</strong> (オレンジ色の丸ボタン) から、操作で困った時の情報を検索できます。</p><p><strong>5 つの入口:</strong></p><table tabindex="0"><thead><tr><th>入口</th><th>用途</th></tr></thead><tbody><tr><td>ホーム</td><td>カテゴリ別ショートカット + 人気の質問 + エラー番号入力欄</td></tr><tr><td>よくある質問 (FAQ)</td><td>カテゴリ別に厳選した Q&amp;A (ログイン・注文・会計・印刷・予約・KDS・メニュー・シフト・テイクアウト・設定)</td></tr><tr><td>キーワード検索</td><td>「会計」「パスワード」「予約」「プリンタ」などで FAQ / 案内記事 / エラーコードを横断検索</td></tr><tr><td>症状からたどる</td><td>「ログインできない」「KDSに出ない」等の症状からステップバイステップの対処手順</td></tr><tr><td>エラー番号</td><td><code>E3024</code> 等を入力すると意味と対処を即座に表示</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">まずはサポートガイドをご利用ください</p><p>サポートガイドには、よくあるお問い合わせと基本的な対処方法をまとめています。該当する案内が見つからない場合は、POSLAサポートへお問い合わせください。</p></div><h2 id="毎日の確認タイミング" tabindex="-1">毎日の確認タイミング <a class="header-anchor" href="#毎日の確認タイミング" aria-label="Permalink to &quot;毎日の確認タイミング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>タイミング</th><th>見る場所</th><th>確認内容</th></tr></thead><tbody><tr><td>開店前</td><td>初期設定、端末稼働、シフト当日・ヘルプ</td><td>KDS/レジ/ハンディ通信、スタッフ未打刻、予約、品切れ</td></tr><tr><td>ピーク前</td><td>運営コックピット、予約台帳、テイクアウト</td><td>予約遅刻、テイクアウト遅延、低在庫、シフト不足</td></tr><tr><td>問い合わせ時</td><td>全体検索、注文履歴、予約詳細</td><td>注文ID、予約者、顧客情報、会計履歴</td></tr><tr><td>閉店前</td><td>運営コックピット、レジ分析、テイクアウト</td><td>未会計、未締め、準備完了残り、返金待ち</td></tr><tr><td>月次・改善</td><td>レポート、売上ドリル、カート離脱</td><td>売れ筋、低評価、離脱商品、スタッフ実績</td></tr></tbody></table><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>タブが表示されない</td><td>権限と所属店舗を確認してください。</td></tr><tr><td>店舗が選べない</td><td>オーナーまたはマネージャーに所属店舗の設定を確認してください。</td></tr><tr><td>読み込みに失敗する</td><td>再読み込みし、改善しない場合はPOSLAサポートへお問い合わせください。</td></tr><tr><td>表示が古い</td><td>ブラウザ再読み込み、または右下のキャッシュリセットを使ってください。</td></tr><tr><td>端末が稼働していない</td><td>端末稼働状況で最終通信時刻を確認し、該当端末で再ログインしてください。</td></tr></tbody></table>',50)])])}const u=d(h,[["render",l]]);export{c as __pageData,u as default};
